(()=>{"use strict";const t=()=>{document.addEventListener("click",t=>{const e=t.target.closest(".dtq-alert-dismiss");if(!e)return;const s=e.closest(".dtq-alert");if(!s)return;const n=s.closest('[class*="dtq_inline_notice"]')||s.parentElement||s;n.style.transition="opacity 0.4s ease",n.style.opacity="0",window.setTimeout(()=>{n.style.display="none"},400)})};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",t):t()})();